// Pocket Twist Top — a squat, chunky two-start spiral cone sized for a pocket
// and an easy first print. Very steep helix (few turns) + a generous central
// bore make it the most fuse-proof of the set. componentCount === 2 (arms).
// Each blade ends in a point. Treat 1 unit ≈ 1 mm.
const { Manifold, CrossSection } = api;
const p = api.params({
  arms:      { type: 'int',    default: 2,   min: 2,   max: 5,   step: 1,   label: 'Spiral arms' },
  baseR:     { type: 'number', default: 17,  min: 8,   max: 24,  step: 0.5, unit: 'mm', label: 'Base radius' },
  height:    { type: 'number', default: 40,  min: 28,  max: 95,  step: 1,   unit: 'mm', label: 'Height' },
  turns:     { type: 'number', default: 1.6, min: 1,   max: 5,   step: 0.1, label: 'Spiral turns (fewer = steeper)' },
  clearance: { type: 'number', default: 0.5, min: 0.3, max: 1.2, step: 0.05, unit: 'mm', label: 'Print clearance' },
  coreFrac:  { type: 'number', default: 0.42, min: 0,  max: 0.6, step: 0.02, label: 'Central bore (× base R)' },
});
const palette = ['#ec4899', '#14b8a6', '#f5b324', '#7c3aed', '#ef4444'];
const R = p.baseR, H = p.height, arms = p.arms, clr = p.clearance;
const tipR = Math.max(0.5, R * 0.03);          // truncate apex so it resolves, not a stalk
const sTop = tipR / R;                          // shared taper rate for body + bore
// Smooth cone body — every spiral comes from the cuts, so the surface stays clean.
let body = CrossSection.circle(R, 140).extrude(H, 160, 0, sTop);
// Tapered central bore: removes the dense near-axis zone where the blades would
// otherwise fuse on the print, and leaves a wall of constant proportion to the tip.
const boreR = R * p.coreFrac;
if (boreR > 0.4) body = body.subtract(
  CrossSection.circle(boreR, 96).extrude(H + 2, 140, 0, sTop).translate([0, 0, -1]));
// N radial helical slab cutters. Each is a constant-thickness gap (= clr) so the
// clearance stays printable at every height while the cone narrows; that also makes
// each blade pinch to its own sharp point near the top. Fewer turns = steeper helix
// = each blade's plastic stays in its own lane and won't bond to its neighbour.
const ov = boreR + 1.5;
const slab2d = CrossSection.square([R + 6 + ov, clr], false).translate([-ov, -clr / 2]);
const baseCut = slab2d.extrude(H + 8, 340, 360 * p.turns, 1).translate([0, 0, -4]);
let cut = baseCut;
for (let k = 1; k < arms; k++) cut = cut.add(baseCut.rotate([0, 0, (k * 360) / arms]));
const parts = body.subtract(cut).decompose();      // -> componentCount === arms
return api.labeledUnion(parts.map((s, i) => ({ name: 'arm' + i, shape: s, color: palette[i % palette.length] })));
